// CustomerStats is the resolver for the customerStats field.
func (r *queryResolver) CustomerStats(ctx context.Context, input *model.CustomerStatsInput) (*model.CustomerStatsResponse, error) {
	var startDate, endDate *time.Time
	var orderType *string
	var minOrders *int
	if input != nil {
		startDate = input.StartDate
		endDate = input.EndDate
		if input.OrderType != nil {
			ot := input.OrderType.String()
			orderType = &ot
		}
		minOrders = input.MinOrders
	}

	rows, err := r.OrderService.GetCustomerStats(ctx, startDate, endDate, orderType, minOrders)
	if err != nil {
		return nil, fmt.Errorf("failed to get customer stats: %w", err)
	}

	customers := make([]*model.CustomerStats, len(rows))
	totalRevenue := decimal.Zero
	totalOrders := 0

	for i, row := range rows {
		preferredType := model.OrderTypeEnumPickup
		if row.DeliveryCount > row.PickupCount {
			preferredType = model.OrderTypeEnumDelivery
		}

		customers[i] = &model.CustomerStats{
			UserID:             row.UserID,
			FirstName:          row.FirstName,
			LastName:           row.LastName,
			Email:              row.Email,
			PhoneNumber:        row.PhoneNumber,
			RegisteredAt:       row.RegisteredAt,
			TotalOrders:        row.TotalOrders,
			TotalAmount:        row.TotalAmount.StringFixed(2),
			AverageOrderAmount: row.AverageAmount.StringFixed(2),
			FirstOrderDate:     row.FirstOrderDate,
			LastOrderDate:      row.LastOrderDate,
			PreferredOrderType: preferredType,
			DeliveryCount:      row.DeliveryCount,
			PickupCount:        row.PickupCount,
		}

		totalRevenue = totalRevenue.Add(row.TotalAmount)
		totalOrders += row.TotalOrders
	}

	avgOrderValue := decimal.Zero
	if totalOrders > 0 {
		avgOrderValue = totalRevenue.Div(decimal.NewFromInt(int64(totalOrders)))
	}

	return &model.CustomerStatsResponse{
		Summary: &model.CustomerStatsSummary{
			TotalCustomers:    len(customers),
			TotalRevenue:      totalRevenue.StringFixed(2),
			AverageOrderValue: avgOrderValue.StringFixed(2),
			TotalOrders:       totalOrders,
		},
		Customers: customers,
	}, nil
}

// Address is the resolver for the address field.
func (r *userResolver) Address(ctx context.Context, obj *model.User) (*model.Address, error) {
	// Return nil if user has no default address
	if obj.DefaultPlaceID == nil {
		return nil, nil
	}

	// Fetch address from cache using place ID
	addr, err := r.AddressService.GetByPlaceID(ctx, *obj.DefaultPlaceID)
	if err != nil {
		return nil, fmt.Errorf("failed to fetch user's default address: %w", err)
	}

	// Return the converted address
	return ToGQLAddress(addr), nil
}

// Orders is the resolver for the orders field.
func (r *userResolver) Orders(ctx context.Context, obj *model.User) ([]*model.Order, error) {
	loader := orderApplication.GetUserOrderLoader(ctx)

	if loader == nil {
		return nil, fmt.Errorf("no user order loader found")
	}

	// Check for error while loading the orders.
	o, err := loader.Loader.Load(ctx, obj.ID.String())
	if err != nil {
		return nil, fmt.Errorf("failed to load user orders: %w", err)
	}

	// Map the orders to the GraphQL model
	orders := Map(o, func(order *orderDomain.Order) *model.Order {
		return ToGQLOrder(order)
	})

	return orders, nil
}

